import{_ as o,o as a,c as e,a2 as d}from"./chunks/framework.BRk9mohw.js";const p=JSON.parse('{"title":"Obsidian","description":"使用 Obsidian 仓库（纯 Markdown 笔记）并通过 obsidian-cli 进行自动化。","frontmatter":{"name":"obsidian","description":"使用 Obsidian 仓库（纯 Markdown 笔记）并通过 obsidian-cli 进行自动化。","homepage":"https://help.obsidian.md","metadata":{"openclaw":{"emoji":"💎","requires":{"bins":["obsidian-cli"]},"install":[{"id":"brew","kind":"brew","formula":"yakitrak/yakitrak/obsidian-cli","bins":["obsidian-cli"],"label":"安装 obsidian-cli (brew)"}]}}},"headers":[],"relativePath":"skills/obsidian.md","filePath":"skills/obsidian.md"}'),l={name:"skills/obsidian.md"};function n(t,i,c,s,r,u){return a(),e("div",null,[...i[0]||(i[0]=[d('<h1 id="obsidian" tabindex="-1">Obsidian <a class="header-anchor" href="#obsidian" aria-label="Permalink to &quot;Obsidian&quot;">​</a></h1><p>Obsidian 仓库 = 磁盘上的普通文件夹。</p><h2 id="仓库结构-典型" tabindex="-1">仓库结构（典型） <a class="header-anchor" href="#仓库结构-典型" aria-label="Permalink to &quot;仓库结构（典型）&quot;">​</a></h2><ul><li>笔记：<code>*.md</code>（纯文本 Markdown；用任何编辑器编辑）</li><li>配置：<code>.obsidian/</code>（工作区 + 插件设置；通常不从脚本触碰）</li><li>画布：<code>*.canvas</code>（JSON）</li><li>附件：你选择在 Obsidian 设置中选择的文件夹（图片/PDF 等）</li></ul><h2 id="找到活动的仓库" tabindex="-1">找到活动的仓库 <a class="header-anchor" href="#找到活动的仓库" aria-label="Permalink to &quot;找到活动的仓库&quot;">​</a></h2><p>Obsidian 桌面版在这里跟踪仓库（真实来源）：</p><ul><li><code>~/Library/Application Support/obsidian/obsidian.json</code></li></ul><p><code>obsidian-cli</code> 从该文件解析仓库；仓库名称通常是<strong>文件夹名称</strong>（路径后缀）。</p><p>快速的&quot;哪个仓库是活动的 / 笔记在哪里？&quot;</p><ul><li>如果你已经设置了默认值：<code>obsidian-cli print-default --path-only</code></li><li>否则，读取 <code>~/Library/Application Support/obsidian/obsidian.json</code> 并使用 <code>&quot;open&quot;: true</code> 的仓库条目。</li></ul><h2 id="备注" tabindex="-1">备注 <a class="header-anchor" href="#备注" aria-label="Permalink to &quot;备注&quot;">​</a></h2><ul><li>多个仓库很常见（iCloud vs <code>~/Documents</code>、工作/个人等）。不要猜测；读取配置。</li><li>避免在脚本中写入硬编码的仓库路径；优先读取配置或使用 <code>print-default</code>。</li></ul><h2 id="obsidian-cli-快速开始" tabindex="-1">obsidian-cli 快速开始 <a class="header-anchor" href="#obsidian-cli-快速开始" aria-label="Permalink to &quot;obsidian-cli 快速开始&quot;">​</a></h2><p>设置默认仓库（一次）：</p><ul><li><code>obsidian-cli set-default &quot;&lt;vault-folder-name&gt;&quot;</code></li><li><code>obsidian-cli print-default</code> / <code>obsidian-cli print-default --path-only</code></li></ul><p>搜索</p><ul><li><code>obsidian-cli search &quot;query&quot;</code>（笔记名称）</li><li><code>obsidian-cli search-content &quot;query&quot;</code>（笔记内搜索；显示片段 + 行号）</li></ul><p>创建</p><ul><li><code>obsidian-cli create &quot;Folder/New note&quot; --content &quot;...&quot; --open</code></li><li>需要 Obsidian URI 处理程序（<code>obsidian://…</code>）工作（已安装 Obsidian）。</li><li>避免通过 URI 在&quot;隐藏&quot;点文件夹（例如 <code>.something/...</code>）下创建笔记；Obsidian 可能会拒绝。</li></ul><p>移动/重命名（安全的重构）</p><ul><li><code>obsidian-cli move &quot;old/path/note&quot; &quot;new/path/note&quot;</code></li><li>在整个仓库中更新 <code>[[wikilinks]]</code> 和常见 Markdown 链接（这是相对于 <code>mv</code> 的主要优势）。</li></ul><p>删除</p><ul><li><code>obsidian-cli delete &quot;path/note&quot;</code></li></ul><p>在适当的时候优先直接编辑：打开 <code>.md</code> 文件并更改它；Obsidian 会自动识别。</p>',24)])])}const h=o(l,[["render",n]]);export{p as __pageData,h as default};
